123	export function mergeAccountConfig<TConfig extends Record<string, unknown>>(params: {
124	  channelConfig: TConfig | undefined;
125	  accountConfig: Partial<TConfig> | undefined;
126	  omitKeys?: string[];
127	  nestedObjectKeys?: string[];
128	}): TConfig {
129	  const omitKeys = new Set(["accounts", ...(params.omitKeys ?? [])]);
130	  const base = Object.fromEntries(
131	    Object.entries((params.channelConfig ?? {}) as Record<string, unknown>).filter(
132	      ([key]) => !omitKeys.has(key),
133	    ),
134	  ) as TConfig;
135	  const merged = {
136	    ...base,
137	    ...params.accountConfig,
138	  };
139	  for (const key of params.nestedObjectKeys ?? []) {
140	    const baseValue = base[key as keyof TConfig];
141	    const accountValue = params.accountConfig?.[key as keyof TConfig];
142	    if (
143	      typeof baseValue === "object" &&
144	      baseValue != null &&
145	      !Array.isArray(baseValue) &&
146	      typeof accountValue === "object" &&
147	      accountValue != null &&
148	      !Array.isArray(accountValue)
149	    ) {
150	      (merged as Record<string, unknown>)[key] = {
151	        ...(baseValue as Record<string, unknown>),
152	        ...(accountValue as Record<string, unknown>),
153	      };
154	    }
155	  }
156	  return merged;
157	}
