176	function resolveLinkedPeerId(params: {
177	  identityLinks?: Record<string, string[]>;
178	  channel: string;
179	  peerId: string;
180	}): string | null {
181	  const identityLinks = params.identityLinks;
182	  if (!identityLinks) {
183	    return null;
184	  }
185	  const peerId = params.peerId.trim();
186	  if (!peerId) {
187	    return null;
188	  }
189	  const candidates = new Set<string>();
190	  const rawCandidate = normalizeToken(peerId);
191	  if (rawCandidate) {
192	    candidates.add(rawCandidate);
193	  }
194	  const channel = normalizeToken(params.channel);
195	  if (channel) {
196	    const scopedCandidate = normalizeToken(`${channel}:${peerId}`);
197	    if (scopedCandidate) {
198	      candidates.add(scopedCandidate);
199	    }
200	  }
201	  if (candidates.size === 0) {
202	    return null;
203	  }
204	  for (const [canonical, ids] of Object.entries(identityLinks)) {
205	    const canonicalName = canonical.trim();
206	    if (!canonicalName) {
207	      continue;
208	    }
209	    if (!Array.isArray(ids)) {
210	      continue;
211	    }
212	    for (const id of ids) {
213	      const normalized = normalizeToken(id);
214	      if (normalized && candidates.has(normalized)) {
215	        return canonicalName;
216	      }
217	    }
218	  }
219	  return null;
220	}
