80	/** Match chat-aware allowlist entries against sender, chat id, guid, or identifier fields. */
81	export function isAllowedParsedChatSender<TParsed extends ParsedChatAllowTarget>(params: {
82	  allowFrom: Array<string | number>;
83	  sender: string;
84	  chatId?: number | null;
85	  chatGuid?: string | null;
86	  chatIdentifier?: string | null;
87	  normalizeSender: (sender: string) => string;
88	  parseAllowTarget: (entry: string) => TParsed;
89	}): boolean {
90	  const allowFrom = params.allowFrom.map((entry) => String(entry).trim());
91	  if (allowFrom.length === 0) {
92	    return false;
93	  }
94	  if (allowFrom.includes("*")) {
95	    return true;
96	  }
97	
98	  const senderNormalized = params.normalizeSender(params.sender);
99	  const chatId = params.chatId ?? undefined;
100	  const chatGuid = params.chatGuid?.trim();
101	  const chatIdentifier = params.chatIdentifier?.trim();
102	
103	  for (const entry of allowFrom) {
104	    if (!entry) {
105	      continue;
106	    }
107	    const parsed = params.parseAllowTarget(entry);
108	    if (parsed.kind === "chat_id" && chatId !== undefined) {
109	      if (parsed.chatId === chatId) {
110	        return true;
111	      }
112	    } else if (parsed.kind === "chat_guid" && chatGuid) {
113	      if (parsed.chatGuid === chatGuid) {
114	        return true;
115	      }
116	    } else if (parsed.kind === "chat_identifier" && chatIdentifier) {
117	      if (parsed.chatIdentifier === chatIdentifier) {
118	        return true;
119	      }
120	    } else if (parsed.kind === "handle" && senderNormalized) {
121	      if (parsed.handle === senderNormalized) {
122	        return true;
123	      }
124	    }
125	  }
126	  return false;
127	}
