51	export async function sendMessageIrc(
52	  to: string,
53	  text: string,
54	  opts: SendIrcOptions = {},
55	): Promise<SendIrcResult> {
56	  const runtime = getIrcRuntime();
57	  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
58	  const account = resolveIrcAccount({
59	    cfg,
60	    accountId: opts.accountId,
61	  });
62	
63	  if (!account.configured) {
64	    throw new Error(
65	      `IRC is not configured for account "${account.accountId}" (need host and nick in channels.irc).`,
66	    );
67	  }
68	
69	  const target = resolveTarget(to, opts);
70	  const tableMode = resolveMarkdownTableMode({
71	    cfg,
72	    channel: "irc",
73	    accountId: account.accountId,
74	  });
75	  const prepared = convertMarkdownTables(text.trim(), tableMode);
76	  const payload = opts.replyTo ? `${prepared}\n\n[reply:${opts.replyTo}]` : prepared;
77	
78	  if (!payload.trim()) {
79	    throw new Error("Message must be non-empty for IRC sends");
80	  }
81	
82	  const client = opts.client;
83	  if (client?.isReady()) {
84	    client.sendPrivmsg(target, payload);
85	  } else {
