import type {
  BaseProbeResult,
  BlockStreamingCoalesceConfig,
  DmConfig,
  DmPolicy,
  GroupPolicy,
  GroupToolPolicyBySenderConfig,
  GroupToolPolicyConfig,
  MarkdownConfig,
  OpenClawConfig,
} from "./runtime-api.js";

/** Per-board (group) configuration, applied to a single named board or the wildcard "*". */
export type PulseBoardBoardConfig = {
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
  toolsBySender?: GroupToolPolicyBySenderConfig;
  skills?: string[];
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

/** Account-level configuration merged from root config and per-account overrides. */
export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  serverUrl?: string;
  username?: string;
  /** API token for authentication. */
  token?: string;
  /** File path to read the token from (rejects symlinks). */
  tokenFile?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  defaultTo?: string;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  /** Per-board configuration keyed by board name (e.g. "!general") or "*" wildcard. */
  boards?: Record<string, PulseBoardBoardConfig>;
  /** Board names to subscribe to on connect (e.g. ["!general", "!ops"]). */
  boardSubscriptions?: string[];
  markdown?: MarkdownConfig;
  historyLimit?: number;
  dmHistoryLimit?: number;
  dms?: Record<string, DmConfig>;
  textChunkLimit?: number;
  chunkMode?: "length" | "newline";
  blockStreaming?: boolean;
  blockStreamingCoalesce?: BlockStreamingCoalesceConfig;
  responsePrefix?: string;
  mediaMaxMb?: number;
};

/** Top-level channels.pulseboard config, supporting optional multi-account layout. */
export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

/** Extended root config type scoped to channels.pulseboard. */
export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

/** A single inbound message received from the PulseBoard service. */
export type PulseBoardInboundMessage = {
  messageId: string;
  /** Conversation peer id: board name for groups, sender username for DMs. */
  target: string;
  /** Raw PulseBoard target (board name for groups, recipient username for DMs). */
  rawTarget?: string;
  senderUsername: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

/** Result of a PulseBoard connectivity probe. */
export type PulseBoardProbe = BaseProbeResult<string> & {
  serverUrl: string;
  username: string;
  latencyMs?: number;
};

