import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { describe, expect, it } from "vitest";
import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
} from "./accounts.js";
import type { CoreConfig } from "./types.js";

function asConfig(value: unknown): CoreConfig {
  return value as CoreConfig;
}

describe("listPulseBoardAccountIds", () => {
  it("returns default when no accounts are configured", () => {
    expect(listPulseBoardAccountIds(asConfig({}))).toEqual(["default"]);
  });

  it("normalizes, deduplicates, and sorts configured account ids", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          accounts: {
            "Ops Team": {},
            "ops-team": {},
            Work: {},
          },
        },
      },
    });

    expect(listPulseBoardAccountIds(cfg)).toEqual(["ops-team", "work"]);
  });
});

describe("resolveDefaultPulseBoardAccountId", () => {
  it("prefers configured defaultAccount when it matches a known account", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          defaultAccount: "Ops Team",
          accounts: {
            default: {},
            "ops-team": {},
          },
        },
      },
    });

    expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("ops-team");
  });

  it("falls back to default when configured defaultAccount is missing", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          defaultAccount: "missing",
          accounts: {
            default: {},
            work: {},
          },
        },
      },
    });

    expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("default");
  });

  it("falls back to first sorted account when default is absent", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          accounts: {
            zzz: {},
            aaa: {},
          },
        },
      },
    });

    expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("aaa");
  });
});

describe("resolvePulseBoardAccount", () => {
  it("resolves serverUrl and username from config", () => {
    const account = resolvePulseBoardAccount({
      cfg: asConfig({
        channels: {
          pulseboard: {
            serverUrl: "https://pb.example.com",
            username: "clawbot",
          },
        },
      }),
    });

    expect(account.serverUrl).toBe("https://pb.example.com");
    expect(account.username).toBe("clawbot");
    expect(account.configured).toBe(true);
  });

  it("returns configured=false when serverUrl or username is missing", () => {
    const account = resolvePulseBoardAccount({
      cfg: asConfig({ channels: { pulseboard: { username: "clawbot" } } }),
    });

    expect(account.configured).toBe(false);
  });

  it("matches normalized configured account ids", () => {
    const account = resolvePulseBoardAccount({
      cfg: asConfig({
        channels: {
          pulseboard: {
            accounts: {
              "Ops Team": {
                serverUrl: "https://pb.example.com",
                username: "clawbot",
              },
            },
          },
        },
      }),
      accountId: "ops-team",
    });

    expect(account.accountId).toBe("ops-team");
    expect(account.serverUrl).toBe("https://pb.example.com");
    expect(account.configured).toBe(true);
  });

  it("reads PULSEBOARD_SERVER_URL and PULSEBOARD_USERNAME from env for the default account", () => {
    const prevUrl = process.env.PULSEBOARD_SERVER_URL;
    const prevUser = process.env.PULSEBOARD_USERNAME;
    process.env.PULSEBOARD_SERVER_URL = "https://env.pb.example.com";
    process.env.PULSEBOARD_USERNAME = "envbot";

    try {
      const account = resolvePulseBoardAccount({ cfg: asConfig({}) });
      expect(account.serverUrl).toBe("https://env.pb.example.com");
      expect(account.username).toBe("envbot");
      expect(account.configured).toBe(true);
    } finally {
      if (prevUrl === undefined) delete process.env.PULSEBOARD_SERVER_URL;
      else process.env.PULSEBOARD_SERVER_URL = prevUrl;
      if (prevUser === undefined) delete process.env.PULSEBOARD_USERNAME;
      else process.env.PULSEBOARD_USERNAME = prevUser;
    }
  });

  it("reads PULSEBOARD_TOKEN from env for the default account", () => {
    const prevToken = process.env.PULSEBOARD_TOKEN;
    process.env.PULSEBOARD_TOKEN = "env-secret-token";

    try {
      const account = resolvePulseBoardAccount({
        cfg: asConfig({
          channels: {
            pulseboard: {
              serverUrl: "https://pb.example.com",
              username: "clawbot",
            },
          },
        }),
      });
      expect(account.token).toBe("env-secret-token");
      expect(account.tokenSource).toBe("env");
    } finally {
      if (prevToken === undefined) delete process.env.PULSEBOARD_TOKEN;
      else process.env.PULSEBOARD_TOKEN = prevToken;
    }
  });

  it.runIf(process.platform !== "win32")("rejects symlinked token files", () => {
    const dir = fs.mkdtempSync(path.join(os.tmpdir(), "openclaw-pulseboard-account-"));
    const tokenFile = path.join(dir, "token.txt");
    const tokenLink = path.join(dir, "token-link.txt");
    fs.writeFileSync(tokenFile, "real-token\n", "utf8");
    fs.symlinkSync(tokenFile, tokenLink);

    const cfg = asConfig({
      channels: {
        pulseboard: {
          serverUrl: "https://pb.example.com",
          username: "clawbot",
          tokenFile: tokenLink,
        },
      },
    });

    const account = resolvePulseBoardAccount({ cfg });
    expect(account.token).toBe("");
    expect(account.tokenSource).toBe("none");
    fs.rmSync(dir, { recursive: true, force: true });
  });
});

