import type { PulseBoardInboundMessage } from "./types.js";

/** Board targets on PulseBoard are prefixed with "!" (e.g. "!general"). */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("!");
}

/** Returns a unique message id for PulseBoard messages. */
export function makePulseBoardMessageId(): string {
  return crypto.randomUUID();
}

const PULSEBOARD_TARGET_PATTERN = /^[^\s]+$/u;

/** True when the raw string looks like a valid PulseBoard target id. */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  return PULSEBOARD_TARGET_PATTERN.test(trimmed);
}

/**
 * Normalize a messaging target string.
 *
 * Supports prefixes: "pulseboard:", "board:" (adds "!" if missing), "user:".
 * Board targets must start with "!"; DM targets are plain usernames.
 */
export function normalizePulseBoardTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  let target = trimmed;
  const lowered = target.toLowerCase();

  if (lowered.startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith("!")) {
      target = `!${target}`;
    }
  }
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }

  if (!target || !looksLikePulseBoardTargetId(target)) {
    return undefined;
  }
  return target;
}

/** Lowercase and strip known prefixes from an allowlist entry. */
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  return value.trim();
}

/** Normalize an entire allowFrom array, dropping empty entries. */
export function normalizePulseBoardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? [])
    .map((entry) => normalizePulseBoardAllowEntry(String(entry)))
    .filter(Boolean);
}

/**
 * Build the set of allowlist candidates for an inbound message.
 *
 * PulseBoard identifies senders only by username, so the candidate list is
 * just the lowercased username.
 */
export function buildPulseBoardAllowlistCandidates(message: PulseBoardInboundMessage): string[] {
  const username = message.senderUsername.trim().toLowerCase();
  if (!username) {
    return [];
  }
  return [username];
}

/** Check whether a message's sender appears in the provided allowlist. */
export function resolvePulseBoardAllowlistMatch(params: {
  allowFrom: string[];
  message: PulseBoardInboundMessage;
}): { allowed: boolean; source?: string } {
  const allowSet = new Set(
    params.allowFrom.map((entry) => entry.trim().toLowerCase()).filter(Boolean),
  );
  if (allowSet.has("*")) {
    return { allowed: true, source: "wildcard" };
  }
  const candidates = buildPulseBoardAllowlistCandidates(params.message);
  for (const candidate of candidates) {
    if (allowSet.has(candidate)) {
      return { allowed: true, source: candidate };
    }
  }
  return { allowed: false };
}

