import { describe, expect, it } from "vitest";
import {
  buildPulseBoardAllowlistCandidates,
  isBoardTarget,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardTarget,
  resolvePulseBoardAllowlistMatch,
} from "./normalize.js";

describe("isBoardTarget", () => {
  it("returns true for board-prefixed targets", () => {
    expect(isBoardTarget("!general")).toBe(true);
    expect(isBoardTarget("!ops")).toBe(true);
  });

  it("returns false for direct message targets", () => {
    expect(isBoardTarget("alice")).toBe(false);
    expect(isBoardTarget("")).toBe(false);
  });
});

describe("normalizePulseBoardTarget", () => {
  it("strips pulseboard: prefix", () => {
    expect(normalizePulseBoardTarget("pulseboard:!general")).toBe("!general");
  });

  it("strips board: prefix and adds ! when missing", () => {
    expect(normalizePulseBoardTarget("board:general")).toBe("!general");
    expect(normalizePulseBoardTarget("board:!general")).toBe("!general");
  });

  it("strips user: prefix", () => {
    expect(normalizePulseBoardTarget("user:alice")).toBe("alice");
  });

  it("returns plain target unchanged", () => {
    expect(normalizePulseBoardTarget("!ops")).toBe("!ops");
    expect(normalizePulseBoardTarget("alice")).toBe("alice");
  });

  it("returns undefined for blank or whitespace input", () => {
    expect(normalizePulseBoardTarget("")).toBeUndefined();
    expect(normalizePulseBoardTarget("   ")).toBeUndefined();
    expect(normalizePulseBoardTarget("\n")).toBeUndefined();
  });

  it("strips nested pulseboard: + board: prefixes", () => {
    expect(normalizePulseBoardTarget("pulseboard:board:news")).toBe("!news");
  });
});

describe("normalizePulseBoardAllowEntry", () => {
  it("lowercases and strips pulseboard: prefix", () => {
    expect(normalizePulseBoardAllowEntry("PulseBoard:Alice")).toBe("alice");
  });

  it("strips user: prefix", () => {
    expect(normalizePulseBoardAllowEntry("User:Bob")).toBe("bob");
  });

  it("returns empty string for blank input", () => {
    expect(normalizePulseBoardAllowEntry("   ")).toBe("");
  });
});

describe("buildPulseBoardAllowlistCandidates", () => {
  it("returns lowercased username", () => {
    const message = {
      messageId: "m1",
      target: "!general",
      senderUsername: "Alice",
      text: "hello",
      timestamp: Date.now(),
      isGroup: true,
    };
    expect(buildPulseBoardAllowlistCandidates(message)).toEqual(["alice"]);
  });

  it("returns empty array for blank sender", () => {
    const message = {
      messageId: "m2",
      target: "!ops",
      senderUsername: "  ",
      text: "hi",
      timestamp: Date.now(),
      isGroup: true,
    };
    expect(buildPulseBoardAllowlistCandidates(message)).toEqual([]);
  });
});

describe("resolvePulseBoardAllowlistMatch", () => {
  const message = {
    messageId: "m1",
    target: "!general",
    senderUsername: "Alice",
    text: "hello",
    timestamp: Date.now(),
    isGroup: true,
  };

  it("allows when allowFrom contains wildcard", () => {
    expect(resolvePulseBoardAllowlistMatch({ allowFrom: ["*"], message }).allowed).toBe(true);
  });

  it("allows case-insensitive username match", () => {
    expect(resolvePulseBoardAllowlistMatch({ allowFrom: ["alice"], message }).allowed).toBe(true);
    expect(resolvePulseBoardAllowlistMatch({ allowFrom: ["Alice"], message }).allowed).toBe(true);
  });

  it("denies when sender is not in allowlist", () => {
    expect(resolvePulseBoardAllowlistMatch({ allowFrom: ["bob"], message }).allowed).toBe(false);
  });

  it("denies for empty allowlist", () => {
    expect(resolvePulseBoardAllowlistMatch({ allowFrom: [], message }).allowed).toBe(false);
  });
});

