import { normalizePulseBoardTarget } from "./normalize.js";
import { makePulseBoardMessageId } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";
import { resolvePulseBoardAccount } from "./accounts.js";

export type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
  target?: string;
};

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
};

function recordPulseBoardOutboundActivity(accountId: string): void {
  try {
    getPulseBoardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    // Swallow "runtime not initialized" so callers with an explicit cfg still work
    // without a live runtime (e.g. send tests, CLI sends before gateway starts).
    if (!(error instanceof Error) || error.message !== "PulseBoard runtime not initialized") {
      throw error;
    }
  }
}

function resolveTarget(to: string, opts?: SendPulseBoardOptions): string {
  const fromArg = normalizePulseBoardTarget(to);
  if (fromArg) {
    return fromArg;
  }
  const fromOpt = normalizePulseBoardTarget(opts?.target ?? "");
  if (fromOpt) {
    return fromOpt;
  }
  throw new Error(`Invalid PulseBoard target: ${to}`);
}

/**
 * Send a message to a PulseBoard board or user.
 *
 * Board targets are prefixed with "!" (e.g. "!general"); DM targets are plain
 * usernames (e.g. "alice").
 *
 * TODO: Replace the stub below with a real HTTP POST to
 *   ${serverUrl}/api/v1/messages
 * using the account token for Bearer auth.
 */
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: opts.accountId,
  });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need serverUrl and username in channels.pulseboard).`,
    );
  }

  const target = resolveTarget(to, opts);
  const payload = opts.replyTo ? `${text.trim()}\n\n[reply:${opts.replyTo}]` : text.trim();

  if (!payload.trim()) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  // TODO: Implement actual HTTP POST to PulseBoard API.
  // Example:
  //   await fetch(`${account.serverUrl}/api/v1/messages`, {
  //     method: "POST",
  //     headers: {
  //       "Content-Type": "application/json",
  //       Authorization: `Bearer ${account.token}`,
  //     },
  //     body: JSON.stringify({
  //       target,
  //       text: payload,
  //       replyTo: opts.replyTo,
  //     }),
  //   });

  recordPulseBoardOutboundActivity(account.accountId);

  return {
    messageId: makePulseBoardMessageId(),
    target,
  };
}

