import { beforeEach, describe, expect, it, vi } from "vitest";
import type { CoreConfig } from "./types.js";

// ---------------------------------------------------------------------------
// Hoisted mocks — defined before any imports so vi.mock hoisting works.
// ---------------------------------------------------------------------------
const hoisted = vi.hoisted(() => {
  const loadConfig = vi.fn();
  const record = vi.fn();
  return {
    loadConfig,
    record,
    normalizePulseBoardTarget: vi.fn((value: string) => value.trim() || undefined),
    makePulseBoardMessageId: vi.fn(() => "pb-msg-1"),
  };
});

vi.mock("./normalize.js", () => ({
  normalizePulseBoardTarget: hoisted.normalizePulseBoardTarget,
  makePulseBoardMessageId: hoisted.makePulseBoardMessageId,
}));

vi.mock("./runtime.js", () => ({
  getPulseBoardRuntime: vi.fn(() => ({
    config: { loadConfig: hoisted.loadConfig },
    channel: {
      activity: { record: hoisted.record },
    },
  })),
}));

import { sendMessagePulseBoard } from "./send.js";

// ---------------------------------------------------------------------------

const baseCfg: CoreConfig = {
  channels: {
    pulseboard: {
      serverUrl: "https://pb.example.com",
      username: "clawbot",
    },
  },
} as CoreConfig;

describe("sendMessagePulseBoard", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("uses explicitly provided cfg without loading runtime config", async () => {
    const result = await sendMessagePulseBoard("!general", "hello", { cfg: baseCfg });

    expect(hoisted.loadConfig).not.toHaveBeenCalled();
    expect(result.target).toBe("!general");
    expect(result.messageId).toBe("pb-msg-1");
    expect(hoisted.record).toHaveBeenCalledWith({
      channel: "pulseboard",
      accountId: "default",
      direction: "outbound",
    });
  });

  it("falls back to runtime config when cfg is omitted", async () => {
    hoisted.loadConfig.mockReturnValueOnce(baseCfg);

    const result = await sendMessagePulseBoard("!ops", "ping");

    expect(hoisted.loadConfig).toHaveBeenCalledTimes(1);
    expect(result.target).toBe("!ops");
  });

  it("appends reply-to suffix when replyTo is provided", async () => {
    // Verify the payload construction by checking no error is thrown and
    // the result is well-formed. Actual HTTP call is stubbed.
    const result = await sendMessagePulseBoard("alice", "hi", {
      cfg: baseCfg,
      replyTo: "some-msg-id",
    });
    expect(result.target).toBe("alice");
    expect(result.messageId).toEqual(expect.any(String));
  });

  it("throws when configured=false (missing serverUrl)", async () => {
    const incompleteCfg: CoreConfig = {
      channels: { pulseboard: { username: "clawbot" } },
    } as CoreConfig;

    await expect(
      sendMessagePulseBoard("!general", "hello", { cfg: incompleteCfg }),
    ).rejects.toThrow(/not configured/);
  });

  it("throws when message text is empty", async () => {
    await expect(
      sendMessagePulseBoard("!general", "   ", { cfg: baseCfg }),
    ).rejects.toThrow(/non-empty/);
  });

  it("swallows runtime-not-initialized error during activity recording", async () => {
    hoisted.record.mockImplementationOnce(() => {
      throw new Error("PulseBoard runtime not initialized");
    });

    const result = await sendMessagePulseBoard("!general", "hello", { cfg: baseCfg });
    expect(result.target).toBe("!general");
  });
});

