import type { DmPolicy } from "openclaw/plugin-sdk/config-runtime";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
import {
  createAllowFromSection,
  createPromptParsedAllowFromForAccount,
  createStandardChannelSetupStatus,
  setSetupChannelEnabled,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupDmPolicy, ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import { formatDocsLink } from "openclaw/plugin-sdk/setup";
import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
} from "./accounts.js";
import {
  isBoardTarget,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardTarget,
} from "./normalize.js";
import {
  pulseBoardSetupAdapter,
  setPulseBoardAllowFrom,
  setPulseBoardBoardAccess,
  setPulseBoardDmPolicy,
  updatePulseBoardAccountConfig,
} from "./setup-core.js";
import type { CoreConfig } from "./types.js";

const channel = "pulseboard" as const;
const USE_ENV_FLAG = "__pbUseEnv";

function parseListInput(raw: string): string[] {
  return raw
    .split(/[\n,;]+/g)
    .map((entry) => entry.trim())
    .filter(Boolean);
}

/**
 * Normalize a raw board entry for use in config.
 *
 * Accepts "!general", "general" (adds "!"), or "*" (wildcard).
 */
function normalizeBoardEntry(raw: string): string | null {
  const trimmed = raw.trim();
  if (!trimmed) {
    return null;
  }
  if (trimmed === "*") {
    return "*";
  }
  const normalized = normalizePulseBoardTarget(trimmed) ?? trimmed;
  if (isBoardTarget(normalized)) {
    return normalized;
  }
  // Add "!" prefix if the entry looks like a bare board name without it.
  return `!${normalized.replace(/^!+/, "")}`;
}

const promptPulseBoardAllowFrom = createPromptParsedAllowFromForAccount<CoreConfig>({
  defaultAccountId: (cfg) => resolveDefaultPulseBoardAccountId(cfg),
  noteTitle: "PulseBoard allowlist",
  noteLines: [
    "Allowlist PulseBoard DMs by sender username.",
    "Examples:",
    "- alice",
    "- bob",
    "Multiple entries: comma-separated.",
  ],
  message: "PulseBoard allowFrom (username)",
  placeholder: "alice, bob",
  parseEntries: (raw) => ({
    entries: parseListInput(raw)
      .map((entry) => normalizePulseBoardAllowEntry(entry))
      .filter(Boolean),
  }),
  getExistingAllowFrom: ({ cfg }) => cfg.channels?.pulseboard?.allowFrom ?? [],
  applyAllowFrom: ({ cfg, allowFrom }) => setPulseBoardAllowFrom(cfg, allowFrom),
});

const pulseBoardDmPolicy: ChannelSetupDmPolicy = {
  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) => (cfg as CoreConfig).channels?.pulseboard?.dmPolicy ?? "pairing",
  setPolicy: (cfg, policy: DmPolicy) => setPulseBoardDmPolicy(cfg as CoreConfig, policy),
  promptAllowFrom: async ({ cfg, prompter, accountId }) =>
    await promptPulseBoardAllowFrom({
      cfg: cfg as CoreConfig,
      prompter,
      accountId,
    }),
};

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs serverUrl + username",
    configuredHint: "configured",
    unconfiguredHint: "needs serverUrl + username",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) =>
      listPulseBoardAccountIds(cfg as CoreConfig).some(
        (accountId) =>
          resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
      ),
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: [
      "PulseBoard needs a server URL and a bot username.",
      "An API token is required for authenticated access.",
      'Set channels.pulseboard.groupPolicy="allowlist" and channels.pulseboard.boards for tighter board control.',
      'Note: board messages are mention-gated by default. To allow unmentioned replies, set channels.pulseboard.boards["!board"].requireMention=false.',
      "Env vars supported: PULSEBOARD_SERVER_URL, PULSEBOARD_USERNAME, PULSEBOARD_TOKEN.",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
    shouldShow: ({ cfg, accountId }) =>
      !resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
  },
  prepare: async ({ cfg, accountId, credentialValues, prompter }) => {
    const isDefaultAccount = accountId === DEFAULT_ACCOUNT_ID;
    const envUrl = isDefaultAccount ? process.env.PULSEBOARD_SERVER_URL?.trim() : "";
    const envUsername = isDefaultAccount ? process.env.PULSEBOARD_USERNAME?.trim() : "";
    const resolved = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
    const envReady =
      Boolean(envUrl && envUsername && !resolved.config.serverUrl && !resolved.config.username);

    if (envReady) {
      const useEnv = await prompter.confirm({
        message: "PULSEBOARD_SERVER_URL and PULSEBOARD_USERNAME detected. Use env vars?",
        initialValue: true,
      });
      if (useEnv) {
        return {
          cfg: updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, { enabled: true }),
          credentialValues: { ...credentialValues, [USE_ENV_FLAG]: "1" },
        };
      }
    }

    return {
      cfg: updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, { enabled: true }),
      credentialValues: { ...credentialValues, [USE_ENV_FLAG]: "0" },
    };
  },
  credentials: [],
  textInputs: [
    {
      inputKey: "serverUrl",
      message: "PulseBoard server URL",
      placeholder: "https://pb.example.com",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.serverUrl ||
        undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          serverUrl: value,
        }),
    },
    {
      inputKey: "token",
      message: "PulseBoard username",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.username || undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          username: value,
        }),
    },
    {
      inputKey: "userId",
      message: "PulseBoard API token (leave blank to skip)",
      required: false,
      applyEmptyValue: false,
      currentValue: ({ cfg, accountId }) => {
        const resolved = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
        return resolved.tokenSource === "config" ? resolved.token || undefined : undefined;
      },
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          token: value || undefined,
        }),
    },
    {
      inputKey: "groupChannels",
      message: "Board subscriptions (optional, comma-separated, e.g. !general, !ops)",
      placeholder: "!general, !ops",
      required: false,
      applyEmptyValue: true,
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({
          cfg: cfg as CoreConfig,
          accountId,
        }).config.boardSubscriptions?.join(", "),
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      normalizeValue: ({ value }) =>
        parseListInput(String(value))
          .map((entry) => normalizeBoardEntry(entry))
          .filter((entry): entry is string => Boolean(entry && entry !== "*"))
          .filter((entry) => isBoardTarget(entry))
          .join(", "),
      applySet: async ({ cfg, accountId, value }) => {
        const boards = parseListInput(String(value))
          .map((entry) => normalizeBoardEntry(entry))
          .filter((entry): entry is string => Boolean(entry && entry !== "*"))
          .filter((entry) => isBoardTarget(entry));
        return updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          boardSubscriptions: boards.length > 0 ? boards : undefined,
        });
      },
    },
  ],
  groupAccess: {
    label: "PulseBoard boards",
    placeholder: "!general, !ops, *",
    currentPolicy: ({ cfg, accountId }) =>
      resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.groupPolicy ??
      "allowlist",
    currentEntries: ({ cfg, accountId }) =>
      Object.keys(
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.boards ?? {},
      ),
    updatePrompt: ({ cfg, accountId }) =>
      Boolean(
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.boards,
      ),
    setPolicy: ({ cfg, accountId, policy }) =>
      setPulseBoardBoardAccess(
        cfg as CoreConfig,
        accountId,
        policy,
        [],
        normalizeBoardEntry,
      ),
    resolveAllowlist: async ({ entries }) =>
      [
        ...new Set(entries.map((entry) => normalizeBoardEntry(entry)).filter(Boolean)),
      ] as string[],
    applyAllowlist: ({ cfg, accountId, resolved }) =>
      setPulseBoardBoardAccess(
        cfg as CoreConfig,
        accountId,
        "allowlist",
        resolved as string[],
        normalizeBoardEntry,
      ),
  },
  allowFrom: createAllowFromSection({
    helpTitle: "PulseBoard allowlist",
    helpLines: [
      "Allowlist PulseBoard DMs by sender username.",
      "Examples:",
      "- alice",
      "- bob",
      "Multiple entries: comma-separated.",
    ],
    message: "PulseBoard allowFrom (username)",
    placeholder: "alice, bob",
    invalidWithoutCredentialNote: "Use a PulseBoard username.",
    parseId: (raw) => {
      const normalized = normalizePulseBoardAllowEntry(raw);
      return normalized || null;
    },
    apply: async ({ cfg, allowFrom }) => setPulseBoardAllowFrom(cfg as CoreConfig, allowFrom),
  }),
  finalize: async ({ cfg, accountId, prompter }) => {
    let next = cfg as CoreConfig;

    const resolvedAfterBoards = resolvePulseBoardAccount({ cfg: next, accountId });
    if (resolvedAfterBoards.config.groupPolicy === "allowlist") {
      const boardKeys = Object.keys(resolvedAfterBoards.config.boards ?? {});
      if (boardKeys.length > 0) {
        const wantsMentions = await prompter.confirm({
          message: "Require @mention to reply in PulseBoard boards?",
          initialValue: true,
        });
        if (!wantsMentions) {
          const boards = resolvedAfterBoards.config.boards ?? {};
          const patched = Object.fromEntries(
            Object.entries(boards).map(([key, value]) => [
              key,
              { ...value, requireMention: false },
            ]),
          );
          next = updatePulseBoardAccountConfig(next, accountId, { boards: patched });
        }
      }
    }

    return { cfg: next };
  },
  completionNote: {
    title: "PulseBoard next steps",
    lines: [
      "Next: restart gateway and verify status.",
      "Command: openclaw channels status --probe",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
  },
  dmPolicy: pulseBoardDmPolicy,
  disable: (cfg) => setSetupChannelEnabled(cfg, channel, false),
};

export { pulseBoardSetupAdapter };

